const updateRiskPolicy = `-- name: UpdateRiskPolicy :one
UPDATE risk_policies
SET name = $1
  , sources = $2
  , presidio_entities = $3
  , enabled = $4
  , action = $5
  , auto_name = $6
  , user_message = $7
  , version = CASE
      WHEN sources IS DISTINCT FROM $2
        OR presidio_entities IS DISTINCT FROM $3
        OR enabled IS DISTINCT FROM $4
        OR action IS DISTINCT FROM $5
      THEN version + 1
      ELSE version
    END
  , updated_at = clock_timestamp()
WHERE id = $8
  AND project_id = $9
  AND deleted IS FALSE
RETURNING id, project_id, organization_id, enabled, name, sources, presidio_entities, action, auto_name, user_message, version, created_at, updated_at, deleted_at, deleted
`

type UpdateRiskPolicyParams struct {
	Name             string
	Sources          []string
	PresidioEntities []string
	Enabled          bool
	Action           string
	AutoName         bool
	UserMessage      pgtype.Text
	ID               uuid.UUID
	ProjectID        uuid.UUID
}

func (q *Queries) UpdateRiskPolicy(ctx context.Context, arg UpdateRiskPolicyParams) (RiskPolicy, error) {
	row := q.db.QueryRow(ctx, updateRiskPolicy,
		arg.Name,
		arg.Sources,
		arg.PresidioEntities,
		arg.Enabled,
		arg.Action,
		arg.AutoName,
		arg.UserMessage,
		arg.ID,
		arg.ProjectID,
	)
	var i RiskPolicy
	err := row.Scan(
		&i.ID,
		&i.ProjectID,
		&i.OrganizationID,
		&i.Enabled,
		&i.Name,
		&i.Sources,
		&i.PresidioEntities,
		&i.Action,
		&i.AutoName,
		&i.UserMessage,
		&i.Version,
		&i.CreatedAt,
		&i.UpdatedAt,
		&i.DeletedAt,
		&i.Deleted,
	)
	return i, err
}
